const REPORT_FAVICON_SRC = "data:image/png;base64,"

const loadCanvasImage = (src: string) =>
  new Promise<HTMLImageElement | null>((resolve) => {
    if (!src) return resolve(null)
    const image = new Image()
    image.onload = () => resolve(image)
    image.onerror = () => resolve(null)
    image.src = src
  })

const drawRoundedRect = (ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number) => {
  ctx.beginPath()
  ctx.moveTo(x + r, y)
  ctx.arcTo(x + w, y, x + w, y + h, r)
  ctx.arcTo(x + w, y + h, x, y + h, r)
  ctx.arcTo(x, y + h, x, y, r)
  ctx.arcTo(x, y, x + w, y, r)
  ctx.closePath()
}

const fillRoundedRect = (ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number, fill: string) => {
  drawRoundedRect(ctx, x, y, w, h, r)
  ctx.fillStyle = fill
  ctx.fill()
}

const strokeRoundedRect = (ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number, stroke: string, width = 1) => {
  drawRoundedRect(ctx, x, y, w, h, r)
  ctx.strokeStyle = stroke
  ctx.lineWidth = width
  ctx.stroke()
}

const createSoftGlow = (ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, color: string) => {
  ctx.save()
  ctx.shadowBlur = 24
  ctx.shadowColor = color
  strokeRoundedRect(ctx, x, y, w, h, 18, color, 1.4)
  ctx.restore()
}

const drawCanvasText = (
  ctx: CanvasRenderingContext2D,
  text: string,
  x: number,
  y: number,
  opts?: { size?: number; color?: string; weight?: string; align?: CanvasTextAlign; alpha?: number }
) => {
  ctx.save()
  ctx.globalAlpha = opts?.alpha ?? 1
  ctx.fillStyle = opts?.color || '#ffffff'
  ctx.font = `${opts?.weight || '400'} ${opts?.size || 18}px Inter, Arial, sans-serif`
  ctx.textAlign = opts?.align || 'left'
  ctx.fillText(text, x, y)
  ctx.restore()
}

const drawDivider = (ctx: CanvasRenderingContext2D, x1: number, y1: number, x2: number, y2: number, color = 'rgba(255,255,255,0.08)', width = 1) => {
  ctx.beginPath()
  ctx.moveTo(x1, y1)
  ctx.lineTo(x2, y2)
  ctx.lineWidth = width
  ctx.strokeStyle = color
  ctx.stroke()
}

const formatReportMoney = (currency: string, n: number) => {
  try {
    return new Intl.NumberFormat(undefined, { style: 'currency', currency, maximumFractionDigits: 0 }).format(n)
  } catch {
    return `${n.toFixed(0)}`
  }
}

const getResponsivePageSize = (desktop = 4, tablet = 3, mobile = 2) => {
  if (typeof window === 'undefined') return desktop
  const width = window.innerWidth
  if (width <= 480) return mobile
  if (width <= 1024) return tablet
  return desktop
}

function PaginationControls({ page, totalPages, onPrev, onNext }: { page: number; totalPages: number; onPrev: () => void; onNext: () => void }) {
  if (totalPages <= 1) return null
  return (
    <div className="paginationFooter">
      <button type="button" className="icon paginationArrowBtn" onClick={onPrev} disabled={page <= 1} aria-label="Previous page">‹</button>
      <span className="paginationLabel">{page} of {totalPages}</span>
      <button type="button" className="icon paginationArrowBtn" onClick={onNext} disabled={page >= totalPages} aria-label="Next page">›</button>
    </div>
  )
}

type AppSelectOption = { value: string; label: string; icon?: string | null }

function AppDropdown({
  value,
  options,
  placeholder,
  onChange,
  disabled = false,
}: {
  value: string
  options: AppSelectOption[]
  placeholder: string
  onChange: (next: string) => void
  disabled?: boolean
}) {
  const [open, setOpen] = useState(false)
  const [highlighted, setHighlighted] = useState(0)
  const rootRef = useRef<HTMLDivElement | null>(null)
  const triggerRef = useRef<HTMLButtonElement | null>(null)
  const menuRef = useRef<HTMLDivElement | null>(null)
  const listboxIdRef = useRef(`category-listbox-${Math.random().toString(36).slice(2)}`)
  const [menuStyle, setMenuStyle] = useState<React.CSSProperties>({})
  const selected = options.find((option) => option.value === value) ?? null

  useEffect(() => {
    if (!open) return
    const onPointerDown = (event: MouseEvent) => {
      const target = event.target as Node
      if (rootRef.current?.contains(target)) return
      if (menuRef.current?.contains(target)) return
      setOpen(false)
    }
    const onEscape = (event: KeyboardEvent) => {
      if (event.key === 'Escape') setOpen(false)
    }
    document.addEventListener('mousedown', onPointerDown)
    document.addEventListener('keydown', onEscape)
    return () => {
      document.removeEventListener('mousedown', onPointerDown)
      document.removeEventListener('keydown', onEscape)
    }
  }, [open])

  useEffect(() => {
    if (!open) return
    const selectedIndex = Math.max(0, options.findIndex((option) => option.value === value))
    setHighlighted(selectedIndex)
  }, [open, options, value])
  useEffect(() => {
    if (!open) return
    const sync = () => {
      const rect = triggerRef.current?.getBoundingClientRect()
      if (!rect) return
      const viewportH = window.innerHeight
      const menuH = Math.min(260, Math.max(160, viewportH * 0.4))
      const openUp = rect.bottom + menuH > viewportH - 12 && rect.top > menuH + 12
      setMenuStyle({
        position: 'fixed',
        left: Math.max(10, rect.left),
        top: openUp ? Math.max(8, rect.top - menuH - 6) : Math.min(viewportH - 8, rect.bottom + 6),
        width: rect.width,
        maxHeight: `${menuH}px`,
      })
    }
    sync()
    window.addEventListener('resize', sync)
    window.addEventListener('scroll', sync, true)
    return () => {
      window.removeEventListener('resize', sync)
      window.removeEventListener('scroll', sync, true)
    }
  }, [open])

  return (
    <div className={`categoryDropdown ${open ? 'open' : ''} ${disabled ? 'disabled' : ''}`} ref={rootRef}>
      <button
        type="button"
        ref={triggerRef}
        className="categoryDropdownTrigger"
        aria-haspopup="listbox"
        aria-expanded={open}
        aria-controls={listboxIdRef.current}
        disabled={disabled}
        onClick={() => setOpen((prev) => !prev)}
        onKeyDown={(event) => {
          if (event.key === 'ArrowDown' || event.key === 'ArrowUp' || event.key === 'Enter' || event.key === ' ') {
            event.preventDefault()
            setOpen(true)
          }
        }}
      >
        <span className="categoryDropdownValue">
          <span className="categoryDropdownIconBubble">{selected?.icon ?? '🏷️'}</span>
          <span className={selected ? '' : 'muted'}>{selected?.label ?? placeholder}</span>
        </span>
        <span className="categoryDropdownChevron" aria-hidden="true">▾</span>
      </button>
      {open ? createPortal((
        <div className="categoryDropdownMenu" ref={menuRef} style={menuStyle} id={listboxIdRef.current} role="listbox" tabIndex={-1}>
          {options.map((option, index) => {
            const isSelected = option.value === value
            const isActive = index === highlighted
            return (
              <button
                type="button"
                role="option"
                aria-selected={isSelected}
                key={option.value}
                className={`categoryDropdownOption ${isSelected ? 'selected' : ''} ${isActive ? 'active' : ''}`}
                onMouseEnter={() => setHighlighted(index)}
                onClick={() => { onChange(option.value); setOpen(false) }}
                onKeyDown={(event) => {
                  if (event.key === 'ArrowDown') { event.preventDefault(); setHighlighted((prev) => Math.min(options.length - 1, prev + 1)) }
                  if (event.key === 'ArrowUp') { event.preventDefault(); setHighlighted((prev) => Math.max(0, prev - 1)) }
                  if (event.key === 'Enter') { event.preventDefault(); onChange(option.value); setOpen(false) }
                  if (event.key === 'Escape') { event.preventDefault(); setOpen(false) }
                }}
              >
                <span className="categoryDropdownOptionLeft">
                  <span className="categoryDropdownIconBubble">{option.icon ?? '🏷️'}</span>
                  <span>{option.label}</span>
                </span>
                {isSelected ? <span className="categoryDropdownCheck">✓</span> : null}
              </button>
            )
          })}
        </div>
      ), document.body) : null}
    </div>
  )
}



const createLegacyReportCanvas = async (options: ReportCanvasOptions) => {
  const canvas = document.createElement('canvas')
  canvas.width = 1400
  canvas.height = 1980
  const ctx = canvas.getContext('2d')
  if (!ctx) return canvas

  const colors = {
    page: '#ffffff',
    panel: '#ffffff',
    panelSoft: '#fbfcfe',
    border: '#d9e1ef',
    text: '#15243d',
    muted: '#66758f',
    accent: '#2f7eff',
    income: '#2f7eff',
    expense: '#f2a93b',
    balance: '#22b07d',
    successBg: '#edf9f4',
    successBorder: '#b8e8cf',
    successText: '#157a56',
    pie: ['#ff6f4a', '#f2a93b', '#4d83ff', '#8bb7ff', '#6fd6c4', '#6a83c8'],
    chartLine: '#1d2f4d',
    grid: '#edf2f9',
  } as const

  const {
    appName, reportTitle, periodLabel, generatedAt, userEmail, totals, overviewRows, donutRows,
    comboTitle, comboRows, comboLineLabel, topCategories, tableTitle, bottomBarTitle, bottomBarRows,
    bottomLineTitle, bottomLineRows, footerText, goalRows = [], expenseTrendRows = [], recurringRows = []
  } = options

  const insights = (options.insights && options.insights.length ? options.insights : []).slice(0, 3)
  const iconImage = await loadCanvasImage(REPORT_FAVICON_SRC)
  const fmt = (n: number) => formatReportMoney(options.currency, n)
  const pct = (value: number, total: number) => (total > 0 ? Math.round((value / total) * 100) : 0)
  const ticks = (maxValue: number) => [0, maxValue / 2, maxValue]

  const M = 42
  const G = 24
  const FULL_W = canvas.width - M * 2

  const text = (value: string, x: number, y: number, opts?: { size?: number; weight?: string; color?: string; align?: CanvasTextAlign }) => {
    ctx.fillStyle = opts?.color || colors.text
    ctx.font = `${opts?.weight || '400'} ${opts?.size || 20}px Arial`
    ctx.textAlign = opts?.align || 'left'
    ctx.fillText(value, x, y)
    ctx.textAlign = 'left'
  }

  const wrapped = (value: string, x: number, y: number, maxWidth: number, opts?: { size?: number; color?: string; lineHeight?: number }) => {
    ctx.fillStyle = opts?.color || colors.text
    ctx.font = `400 ${opts?.size || 17}px Arial`
    const words = value.split(/\s+/)
    let current = ''
    let yy = y
    const lineHeight = opts?.lineHeight || 20
    for (const word of words) {
      const next = current ? `${current} ${word}` : word
      if (ctx.measureText(next).width > maxWidth && current) {
        ctx.fillText(current, x, yy)
        current = word
        yy += lineHeight
      } else {
        current = next
      }
    }
    if (current) ctx.fillText(current, x, yy)
  }

  const divider = (x1: number, y1: number, x2: number, y2: number, color: string = colors.border, width = 1) => {
    ctx.beginPath()
    ctx.moveTo(x1, y1)
    ctx.lineTo(x2, y2)
    ctx.strokeStyle = color
    ctx.lineWidth = width
    ctx.stroke()
  }

  const panel = (x: number, y: number, w: number, h: number, r = 18, fill: string = colors.panel, stroke: string = colors.border) => {
    fillRoundedRect(ctx, x, y, w, h, r, fill)
    strokeRoundedRect(ctx, x, y, w, h, r, stroke, 1)
  }

  ctx.fillStyle = colors.page
  ctx.fillRect(0, 0, canvas.width, canvas.height)

  let y = M

  // Header
  const headerH = 170
  panel(M, y, FULL_W, headerH, 10, '#ffffff', colors.border)
  divider(M, y + 58, M + FULL_W, y + 58, '#e5ebf5')
  if (iconImage) ctx.drawImage(iconImage, M + 18, y + 17, 24, 24)
  text(appName, M + 52, y + 38, { size: 28, weight: '700' })
  text(userEmail || '', M + FULL_W - 18, y + 38, { size: 17, color: colors.text, align: 'right' })
  text(reportTitle, M + 18, y + 98, { size: 38, weight: '700' })
  text(periodLabel, M + 18, y + 132, { size: 23, color: colors.muted })
  text(`Generated on: ${generatedAt}`, M + 18, y + 153, { size: 15, color: colors.muted })
  panel(M + FULL_W - 282, y + 74, 240, 38, 10, colors.successBg, colors.successBorder)
  text(totals.balance >= 0 ? '✚  Good Savings Month' : '✚  Watch Spending Closely', M + FULL_W - 252, y + 98, {
    size: 16, weight: '700', color: colors.successText
  })
  y += headerH + G

  // Summary cards
  const cardH = 100
  const cardGap = 18
  const cardW = (FULL_W - cardGap * 2) / 3
  ;[
    { title: 'Total Income', value: fmt(totals.income), icon: '💰', edge: '#cfe0ff' },
    { title: 'Total Expenses', value: fmt(totals.expenses), icon: '👜', edge: '#ffd8ca' },
    { title: 'Ending Balance', value: fmt(totals.balance), icon: '👛', edge: '#d8e4ff' },
  ].forEach((card, i) => {
    const x = M + i * (cardW + cardGap)
    panel(x, y, cardW, cardH, 16, '#ffffff', card.edge)
    text(card.icon, x + 18, y + 34, { size: 22 })
    text(card.title, x + 54, y + 28, { size: 17, color: colors.muted })
    text(card.value, x + 54, y + 64, { size: 29, weight: '700' })
  })
  y += cardH + 40

  // Overview + breakdown
  const leftW = 405
  const rightW = FULL_W - leftW - G
  text('Monthly Overview', M, y - 6, { size: 24, weight: '700' })
  text('Expense Breakdown', M + leftW + G, y - 6, { size: 24, weight: '700' })
  panel(M, y + 10, leftW, 188, 16, '#ffffff', colors.border)
  overviewRows.slice(0, 3).forEach((row, i) => {
    const ry = y + 66 + i * 46
    fillRoundedRect(ctx, M + 18, ry - 11, 14, 14, 4, i === 2 ? '#56c7b5' : '#3792ff')
    text(`${row.label}:`, M + 50, ry + 1, { size: 18, weight: '700' })
    divider(M + 132, ry - 4, M + 250, ry - 4, '#e7edf7')
    text(row.value.replace('.00', ''), M + leftW - 18, ry + 1, { size: 21, weight: '700', align: 'right', color: i === 2 ? colors.balance : colors.text })
  })

  panel(M + leftW + G, y + 10, rightW, 290, 16, '#ffffff', colors.border)
  const rawDonut = donutRows.length ? donutRows.slice(0, 8) : [{ label: 'Other', value: 1 }]
  const sortedDonut = rawDonut.slice().sort((a, b) => b.value - a.value)
  const majorDonut = sortedDonut.slice(0, 5)
  const remainder = sortedDonut.slice(5).reduce((sum, row) => sum + Math.max(row.value, 0), 0)
  const donutData = remainder > 0 ? [...majorDonut, { label: 'Other', value: remainder }] : majorDonut
  const donutTotal = donutData.reduce((s, r) => s + Math.max(r.value, 0), 0) || 1
  const panelX = M + leftW + G
  const panelY = y + 10
  const donutX = panelX + rightW * 0.66
  const donutY = panelY + 150
  const outer = 82
  const inner = 40
  let angle = -Math.PI / 2
  const leftLabels: Array<{ anchorY: number; text: string; color: string }> = []
  const rightLabels: Array<{ anchorY: number; text: string; color: string }> = []
  donutData.forEach((row, i) => {
    const frac = Math.max(row.value, 0) / donutTotal
    const slice = frac * Math.PI * 2
    ctx.beginPath(); ctx.moveTo(donutX, donutY); ctx.arc(donutX, donutY, outer, angle, angle + slice); ctx.closePath()
    ctx.fillStyle = colors.pie[i % colors.pie.length]
    ctx.fill()
    const mid = angle + slice / 2
    const percentage = pct(row.value, donutTotal)
    if (percentage >= 10) {
      text(`${percentage}%`, donutX + Math.cos(mid) * 54, donutY + Math.sin(mid) * 54 + 5, { size: 16, weight: '700', color: '#ffffff', align: 'center' })
    }
    const shortLabel = row.label.length > 17 ? `${row.label.slice(0, 15)}…` : row.label
    const payload = { anchorY: donutY + Math.sin(mid) * 108, text: `${shortLabel} ${percentage}%`, color: colors.pie[i % colors.pie.length] }
    if (Math.cos(mid) >= 0) rightLabels.push(payload)
    else leftLabels.push(payload)
    angle += slice
  })
  const placeLabels = (items: Array<{ anchorY: number; text: string; color: string }>, side: 'left' | 'right') => {
    const sorted = items.sort((a, b) => a.anchorY - b.anchorY)
    const topBound = panelY + 42
    const bottomBound = panelY + 252
    sorted.forEach((item, idx) => {
      let labelY = Math.min(Math.max(item.anchorY, topBound), bottomBound)
      if (idx > 0 && labelY - sorted[idx - 1].anchorY < 20) labelY = sorted[idx - 1].anchorY + 20
      item.anchorY = Math.min(labelY, bottomBound)
    })
    for (let i = sorted.length - 2; i >= 0; i--) {
      if (sorted[i + 1].anchorY - sorted[i].anchorY < 20) sorted[i].anchorY = sorted[i + 1].anchorY - 20
    }
    sorted.forEach((item) => {
      const isRight = side === 'right'
      const endX = isRight ? donutX + 132 : donutX - 132
      const textX = isRight ? endX + 8 : endX - 8
      const targetY = item.anchorY
      const angleGuess = Math.atan2(targetY - donutY, (isRight ? 1 : -1) * 90)
      const startX = donutX + Math.cos(angleGuess) * outer
      const startY = donutY + Math.sin(angleGuess) * outer
      const elbowX = donutX + (isRight ? 102 : -102)
      divider(startX, startY, elbowX, targetY, item.color, 1.5)
      divider(elbowX, targetY, endX, targetY, item.color, 1.5)
      text(item.text, textX, targetY + 5, { size: 13, weight: '700', color: colors.text, align: isRight ? 'left' : 'right' })
    })
  }
  placeLabels(leftLabels, 'left')
  placeLabels(rightLabels, 'right')
  ctx.beginPath(); ctx.arc(donutX, donutY, inner, 0, Math.PI * 2); ctx.fillStyle = '#ffffff'; ctx.fill()
  text(`${pct(donutData[0]?.value || 0, donutTotal)}%`, donutX, donutY + 7, { size: 22, weight: '700', align: 'center' })
  y += 336

  // Spending chart
  text(comboTitle, M, y - 6, { size: 24, weight: '700' })
  const comboH = 208
  panel(M, y + 8, FULL_W, comboH, 16, '#ffffff', colors.border)
  const cx = M + 18
  const cy = y + 28
  const cw = FULL_W - 36
  const ch = 130
  const plotLeft = cx + 42
  const plotRight = cx + cw - 18
  const plotTop = cy + 8
  const plotBottom = cy + ch - 12
  const comboMax = Math.max(...comboRows.map((r) => Math.max(r.income || 0, r.expenses || 0, r.line || 0)), 1)
  ticks(comboMax).forEach((tick, idx) => {
    const n = idx / 2
    const yy = plotBottom - n * (plotBottom - plotTop)
    divider(plotLeft, yy, plotRight, yy, colors.grid)
    text(fmt(tick).replace('.00', ''), plotLeft - 10, yy + 4, { size: 13, color: colors.muted, align: 'right' })
  })
  const step = (plotRight - plotLeft) / Math.max(comboRows.length, 1)
  comboRows.forEach((row, i) => {
    const baseX = plotLeft + i * step + 24
    const bw = 14
    const ih = (Math.max(row.income, 0) / comboMax) * (plotBottom - plotTop)
    const eh = (Math.max(row.expenses, 0) / comboMax) * (plotBottom - plotTop)
    fillRoundedRect(ctx, baseX, plotBottom - ih, bw, ih, 4, colors.income)
    fillRoundedRect(ctx, baseX + bw + 7, plotBottom - eh, bw, eh, 4, colors.expense)
    text(row.label, baseX + 10, plotBottom + 22, { size: 12, color: colors.muted, align: 'center' })
  })
  ctx.beginPath()
  comboRows.forEach((row, i) => {
    const xx = plotLeft + i * step + 40
    const yy = plotBottom - (Math.max(row.line, 0) / comboMax) * (plotBottom - plotTop)
    if (i === 0) ctx.moveTo(xx, yy)
    else ctx.lineTo(xx, yy)
  })
  ctx.strokeStyle = colors.chartLine
  ctx.lineWidth = 2
  ctx.stroke()
  comboRows.forEach((row, i) => {
    const xx = plotLeft + i * step + 40
    const yy = plotBottom - (Math.max(row.line, 0) / comboMax) * (plotBottom - plotTop)
    ctx.beginPath(); ctx.arc(xx, yy, 3, 0, Math.PI * 2); ctx.fillStyle = colors.chartLine; ctx.fill()
  })
  fillRoundedRect(ctx, M + 24, y + 176, 12, 7, 3, colors.income)
  text('Income', M + 44, y + 184, { size: 14, color: colors.muted })
  fillRoundedRect(ctx, M + 126, y + 176, 12, 7, 3, colors.expense)
  text('Expenses', M + 146, y + 184, { size: 14, color: colors.muted })
  divider(M + 252, y + 180, M + 276, y + 180, colors.chartLine, 2)
  text(comboLineLabel, M + 286, y + 184, { size: 14, color: colors.muted })
  y += comboH + G

  // Goals / expense trend or fallback insight / top categories row
  const middleW = (FULL_W - G) / 2
  const middleH = 182
  const middleTitleY = y + 28
  panel(M, y, middleW, middleH, 16, '#ffffff', colors.border)
  panel(M + middleW + G, y, middleW, middleH, 16, '#ffffff', colors.border)

  const activeGoals = goalRows.slice(0, 2)
  if (activeGoals.length) {
    text('Goals', M + 18, middleTitleY, { size: 24, weight: '700' })
    activeGoals.forEach((goal, i) => {
      const gy = y + 68 + i * 58
      const safeTarget = Math.max(goal.target, 0)
      const safeCurrent = Math.max(goal.current, 0)
      const progress = safeTarget > 0 ? Math.min(1, safeCurrent / safeTarget) : 0
      const icon = goal.emoji || (i === 0 ? '✅' : '🎯')
      fillRoundedRect(ctx, M + 18, gy - 12, 28, 28, 8, '#f4f7fb')
      text(icon, M + 32, gy + 7, { size: 16, align: 'center' })
      text(goal.label, M + 62, gy, { size: 17, weight: '700' })
      text(`Save ${fmt(safeTarget)}`, M + middleW - 18, gy, { size: 14, weight: '700', color: colors.text, align: 'right' })
      fillRoundedRect(ctx, M + 62, gy + 12, middleW - 106, 8, 4, '#dfe8f5')
      fillRoundedRect(ctx, M + 62, gy + 12, (middleW - 106) * progress, 8, 4, i === 0 ? '#4cc38a' : '#3792ff')
      text(`${fmt(safeCurrent)} of ${fmt(safeTarget)} completed`, M + 62, gy + 34, { size: 13, color: colors.muted })
    })
  } else {
    text('Insight', M + 18, middleTitleY, { size: 18, weight: '700' })
    const fallbackInsights = [
      `You spent ${pct(donutData[0]?.value || 0, donutTotal)}% of your budget on ${donutData[0]?.label || 'top category'}.`,
      totals.balance >= 0 ? `Your ending balance is ${fmt(totals.balance)}.` : `Your balance is negative by ${fmt(Math.abs(totals.balance))}.`,
      `${(donutData[1]?.label || 'Secondary category')} spending is trending upward - monitor closely.`,
    ]
    ;(insights.length ? insights : fallbackInsights).slice(0, 3).forEach((item, i) => {
      text('•', M + 24, y + 56 + i * 24, { size: 15, weight: '700', color: colors.accent })
      wrapped(item, M + 40, y + 56 + i * 24, middleW - 60, { size: 13, lineHeight: 17 })
    })
  }

  text(expenseTrendRows.length ? 'Expense Trend' : 'Top Categories', M + middleW + G + 16, middleTitleY, { size: 24, weight: '700' })
  if (expenseTrendRows.length) {
    const ex = M + middleW + G + 16
    const ey = y + 56
    const ew = middleW - 32
    const eh = 96
    const trendMax = Math.max(...expenseTrendRows.map((row) => row.value), 1)
    ticks(trendMax).forEach((tick, idx) => {
      const n = idx / 2
      const yy = ey + eh - n * eh
      divider(ex + 36, yy, ex + ew - 10, yy, colors.grid)
      text(fmt(tick).replace('.00', ''), ex + 26, yy + 4, { size: 11, color: colors.muted, align: 'right' })
    })
    ctx.beginPath()
    expenseTrendRows.forEach((row, i) => {
      const xx = ex + 50 + (i / Math.max(expenseTrendRows.length - 1, 1)) * (ew - 72)
      const yy = ey + eh - (Math.max(row.value, 0) / trendMax) * eh
      if (i === 0) ctx.moveTo(xx, yy)
      else ctx.lineTo(xx, yy)
    })
    ctx.strokeStyle = colors.expense
    ctx.lineWidth = 2.5
    ctx.stroke()
    expenseTrendRows.forEach((row, i) => {
      const xx = ex + 50 + (i / Math.max(expenseTrendRows.length - 1, 1)) * (ew - 72)
      const yy = ey + eh - (Math.max(row.value, 0) / trendMax) * eh
      ctx.beginPath(); ctx.arc(xx, yy, 3.5, 0, Math.PI * 2); ctx.fillStyle = colors.expense; ctx.fill()
      text(row.label, xx, ey + eh + 23, { size: 11, color: colors.muted, align: 'center' })
    })
    const last = expenseTrendRows[expenseTrendRows.length - 1]
    if (last) {
      const xx = ex + 50 + (Math.max(expenseTrendRows.length - 1, 0) / Math.max(expenseTrendRows.length - 1, 1)) * (ew - 72)
      const yy = ey + eh - (Math.max(last.value, 0) / trendMax) * eh
      fillRoundedRect(ctx, xx - 56, yy - 36, 78, 28, 8, '#fdecc3')
      text(fmt(last.value).replace('.00', ''), xx - 17, yy - 17, { size: 13, weight: '700', color: '#6f5213', align: 'center' })
    }
  } else {
    topCategories.slice(0, 3).forEach((row, i) => {
      const ry = y + 56 + i * 26
      text(`${i + 1}.`, M + middleW + G + 18, ry, { size: 13, weight: '700' })
      text(row.label, M + middleW + G + 42, ry, { size: 13 })
      text(row.value, M + FULL_W - 18, ry, { size: 13, weight: '700', align: 'right' })
    })
  }
  y += middleH + 110

  // Bottom charts
  const bottomW = (FULL_W - G) / 2
  const bottomH = 240
  text(tableTitle, M, y - 12, { size: 24, weight: '700' })
  text(bottomLineTitle, M + bottomW + G, y - 12, { size: 21, weight: '700' })
  panel(M, y, bottomW, bottomH, 16, '#ffffff', colors.border)
  panel(M + bottomW + G, y, bottomW, bottomH, 16, '#ffffff', colors.border)

  const bX = M + 18
  const bY = y + 24
  const bW = bottomW - 36
  const bH = 138
  const monthBars = bottomBarRows.slice(0, 12)
  const barsMax = Math.max(...monthBars.map((r) => Math.max(r.income, r.expenses)), 1)
  ticks(barsMax).forEach((tick, idx) => {
    const n = idx / 2
    const yy = bY + bH - n * bH
    divider(bX + 28, yy, bX + bW, yy, colors.grid)
    text(fmt(tick).replace('.00', ''), bX + 20, yy + 4, { size: 11, color: colors.muted, align: 'right' })
  })
  monthBars.forEach((row, i) => {
    const slot = (bW - 42) / Math.max(monthBars.length, 1)
    const gx = bX + 38 + i * slot
    const bw = 9
    const ih = (Math.max(row.income, 0) / barsMax) * bH
    const eh = (Math.max(row.expenses, 0) / barsMax) * bH
    fillRoundedRect(ctx, gx, bY + bH - ih, bw, ih, 4, '#58c7b4')
    fillRoundedRect(ctx, gx + bw + 4, bY + bH - eh, bw, eh, 4, '#5a86ff')
    text(row.label, gx + 7, bY + bH + 20, { size: 11, color: colors.muted, align: 'center' })
  })

  const lx = M + bottomW + G + 18
  const ly = y + 24
  const lw = bottomW - 36
  const lh = 138
  const lineRows = bottomLineRows.slice(-12)
  const lineMax = Math.max(...lineRows.map((r) => r.value), 1)
  ticks(lineMax).forEach((tick, idx) => {
    const n = idx / 2
    const yy = ly + lh - n * lh
    divider(lx + 30, yy, lx + lw, yy, colors.grid)
    text(fmt(tick).replace('.00', ''), lx + 24, yy + 4, { size: 10, color: colors.muted, align: 'right' })
  })
  ctx.beginPath()
  lineRows.forEach((row, i) => {
    const xx = lx + 36 + (i / Math.max(lineRows.length - 1, 1)) * (lw - 54)
    const yy = ly + lh - (row.value / lineMax) * lh
    if (i === 0) ctx.moveTo(xx, yy)
    else ctx.lineTo(xx, yy)
  })
  ctx.strokeStyle = colors.accent
  ctx.lineWidth = 3
  ctx.stroke()
  lineRows.forEach((row, i) => {
    const xx = lx + 36 + (i / Math.max(lineRows.length - 1, 1)) * (lw - 54)
    const yy = ly + lh - (row.value / lineMax) * lh
    ctx.beginPath(); ctx.arc(xx, yy, 3.5, 0, Math.PI * 2); ctx.fillStyle = colors.accent; ctx.fill()
    text(row.label, xx, ly + lh + 20, { size: 10, color: colors.muted, align: 'center' })
  })
  if (lineRows.length) {
    const lastPoint = lineRows[lineRows.length - 1]
    const xx = lx + 36 + (Math.max(lineRows.length - 1, 0) / Math.max(lineRows.length - 1, 1)) * (lw - 54)
    const yy = ly + lh - (lastPoint.value / lineMax) * lh
    fillRoundedRect(ctx, xx - 76, yy - 28, 72, 24, 8, '#e7f0ff')
    text(fmt(lastPoint.value).replace('.00', ''), xx - 40, yy - 11, { size: 13, weight: '700', color: colors.accent, align: 'center' })
  }

  y += bottomH + 34

  const footerPanelH = 162
  const footerTitleY = y + 30
  panel(M, y, bottomW, footerPanelH, 16, '#ffffff', colors.border)
  panel(M + bottomW + G, y, bottomW, footerPanelH, 16, '#ffffff', colors.border)
  fillRoundedRect(ctx, M + 14, y + 14, bottomW - 28, 36, 12, '#eef5ff')
  fillRoundedRect(ctx, M + bottomW + G + 14, y + 14, bottomW - 28, 36, 12, '#eefaf4')
  text('🏆 Top Categories', M + 28, footerTitleY, { size: 21, weight: '700' })
  topCategories.slice(0, 4).forEach((row, i) => {
    const ry = y + 68 + i * 24
    const rowColors = ['#fff2e8', '#fff8dc', '#eef6ff', '#f3efff']
    fillRoundedRect(ctx, M + 18, ry - 15, bottomW - 36, 22, 10, rowColors[i % rowColors.length])
    text(['🥇','🥈','🥉','✨'][i] || '•', M + 30, ry + 1, { size: 14 })
    text(row.label, M + 58, ry + 1, { size: 15, weight: '700' })
    text(row.value, M + bottomW - 24, ry + 1, { size: 15, weight: '700', align: 'right' })
  })
  text('🔁 Recurring', M + bottomW + G + 28, footerTitleY, { size: 21, weight: '700' })
  const recurringList = recurringRows.slice(0, 4)
  if (recurringList.length) {
    recurringList.forEach((row, i) => {
      const ry = y + 68 + i * 24
      const rowColors = ['#eefaf4', '#eef6ff', '#fff6e7', '#f7f0ff']
      fillRoundedRect(ctx, M + bottomW + G + 18, ry - 15, bottomW - 36, 22, 10, rowColors[i % rowColors.length])
      const labelText = row.label.length > 24 ? `${row.label.slice(0, 22)}…` : row.label
      text(labelText, M + bottomW + G + 28, ry + 1, { size: 14, weight: '700' })
      fillRoundedRect(ctx, M + FULL_W - 170, ry - 12, 70, 18, 9, '#ffffff')
      text(row.cadence, M + FULL_W - 135, ry + 1, { size: 11, color: colors.muted, align: 'center' })
      text(fmt(row.amount), M + FULL_W - 24, ry + 1, { size: 14, weight: '700', align: 'right' })
    })
  } else {
    fillRoundedRect(ctx, M + bottomW + G + 18, y + 66, bottomW - 36, 30, 10, '#f8fafc')
    text('No recurring items found for this report.', M + bottomW + G + 30, y + 86, { size: 14, color: colors.muted })
  }

  text(footerText, canvas.width / 2, canvas.height - 18, { size: 15, color: colors.muted, align: 'center' })
  return canvas
}


const createMonthlyFinancialReportPdf = async (options: ReportCanvasOptions & { previousMonthLabel?: string; previousTotals?: { income: number; expenses: number; balance: number } | null }) => {
  const PW = 1240
  const PH = 1754
  const canvas = document.createElement('canvas')
  canvas.width = PW * 2
  canvas.height = PH * 2
  const ctx = canvas.getContext('2d')
  if (!ctx) return canvas
  ctx.scale(2, 2)

  // Multi-colour semantic palette on a single light surface (no dark bands).
  const c = {
    bg: '#f4f6fb',
    card: '#ffffff',
    headerBg: '#eef2fb',
    ink: '#0f2245',
    text: '#1c2c47',
    sub: '#5a6b86',
    muted: '#93a1b8',
    line: '#e5ebf3',
    soft: '#f5f8fc',
    white: '#ffffff',
    green: '#0fae6f', greenSoft: '#e7f8f0',
    red: '#f0524b', redSoft: '#fdeceb',
    blue: '#3b73f0', blueSoft: '#eaf1ff',
    violet: '#7c5cf0', violetSoft: '#efeaff',
    amber: '#f6a723', amberSoft: '#fdf0d6',
    pie: ['#3b73f0', '#0fae6f', '#f6a723', '#7c5cf0', '#f0524b', '#14b8c4'],
  } as const

  const {
    appName, reportTitle, periodLabel, generatedAt, userEmail, totals, donutRows, comboRows, comboTitle, goalRows = [], recurringRows = [], insights = [],
    currency, previousMonthLabel, previousTotals,
  } = options

  const fmtMoney = (n: number, withCents = false) => {
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency, minimumFractionDigits: withCents ? 2 : 0, maximumFractionDigits: withCents ? 2 : 0 }).format(n)
    } catch {
      return `${currency}${withCents ? n.toFixed(2) : Math.round(n)}`
    }
  }
  const fmtPct = (n: number) => `${n.toFixed(1)}%`
  const safeIncome = Math.max(0, Number(totals.income || 0))
  const safeExpenses = Math.max(0, Number(totals.expenses || 0))
  const safeNet = Number(totals.balance || 0)
  const savingsRate = safeIncome > 0 ? (safeNet / safeIncome) * 100 : 0
  const statusText = safeNet >= 0 ? 'Healthy Cash Flow' : 'Watch Spending'

  // ---- primitive helpers -------------------------------------------------
  const text = (value: string, x: number, y: number, o?: { size?: number; weight?: string; color?: string; align?: CanvasTextAlign }) => {
    ctx.fillStyle = o?.color ?? c.text
    ctx.font = `${o?.weight ?? '600'} ${o?.size ?? 16}px Inter, "Helvetica Neue", Arial, sans-serif`
    ctx.textAlign = o?.align ?? 'left'
    ctx.fillText(value, x, y)
    ctx.textAlign = 'left'
  }
  const measure = (value: string, size: number, weight = '600') => {
    ctx.font = `${weight} ${size}px Inter, "Helvetica Neue", Arial, sans-serif`
    return ctx.measureText(value).width
  }
  const line = (x1: number, y1: number, x2: number, y2: number, color: string = c.line, w = 1) => {
    ctx.beginPath(); ctx.moveTo(x1, y1); ctx.lineTo(x2, y2); ctx.strokeStyle = color; ctx.lineWidth = w; ctx.stroke()
  }
  const card = (x: number, y: number, w: number, h: number, o?: { r?: number; fill?: string; stroke?: string; shadow?: boolean }) => {
    const r = o?.r ?? 18
    if (o?.shadow !== false) {
      ctx.save()
      ctx.shadowColor = 'rgba(15,34,69,0.10)'
      ctx.shadowBlur = 22
      ctx.shadowOffsetY = 8
      fillRoundedRect(ctx, x, y, w, h, r, o?.fill ?? c.card)
      ctx.restore()
    } else {
      fillRoundedRect(ctx, x, y, w, h, r, o?.fill ?? c.card)
    }
    strokeRoundedRect(ctx, x, y, w, h, r, o?.stroke ?? c.line, 1)
  }
  const sectionTitle = (x: number, y: number, label: string, accent: string, sub?: string) => {
    fillRoundedRect(ctx, x, y - 12, 4, 16, 2, accent)
    text(label, x + 14, y + 2, { size: 15.5, weight: '800', color: c.ink })
    if (sub) text(sub, x + 14, y + 21, { size: 11.5, weight: '600', color: c.muted })
  }
  const arrow = (cx: number, cy: number, up: boolean, color: string, s = 5) => {
    ctx.beginPath()
    if (up) { ctx.moveTo(cx, cy - s); ctx.lineTo(cx + s, cy + s); ctx.lineTo(cx - s, cy + s) }
    else { ctx.moveTo(cx, cy + s); ctx.lineTo(cx + s, cy - s); ctx.lineTo(cx - s, cy - s) }
    ctx.closePath(); ctx.fillStyle = color; ctx.fill()
  }
  const checkMark = (cx: number, cy: number, color: string) => {
    ctx.beginPath(); ctx.moveTo(cx - 4, cy); ctx.lineTo(cx - 1, cy + 3.5); ctx.lineTo(cx + 5, cy - 3.5)
    ctx.strokeStyle = color; ctx.lineWidth = 2.2; ctx.lineCap = 'round'; ctx.lineJoin = 'round'; ctx.stroke(); ctx.lineCap = 'butt'
  }

  // ---- data prep ---------------------------------------------------------
  const categoryRows = (() => {
    const source = (donutRows?.length ? donutRows : [{ label: 'Uncategorized', value: safeExpenses || 1 }]).slice(0, 6)
    const normalized = source.map((row) => ({ ...row, value: Math.max(0, Number(row.value || 0)) }))
    const total = normalized.reduce((s, r) => s + r.value, 0) || 1
    return normalized.map((row, index) => ({ ...row, color: c.pie[index % c.pie.length], pct: (row.value / total) * 100 }))
  })()
  const weekRows = (comboRows?.length ? comboRows : [{ label: 'Week 1', income: safeIncome, expenses: safeExpenses, line: Math.max(safeNet, 0) }]).slice(0, 4)

  // ---- layout grid -------------------------------------------------------
  const PAD = 40
  const CW = PW - PAD * 2
  const HB = 216
  const FB = 72
  const GAP = 20
  const contentTop = HB + 26
  const colGap = 20
  const colW = (CW - colGap) / 2
  const colL = PAD
  const colR = PAD + colW + colGap

  const kpiH = 150
  const chartsH = 470
  const suppH = 366
  const bottomH = 368
  const yKpi = contentTop
  const yCharts = yKpi + kpiH + GAP
  const ySupp = yCharts + chartsH + GAP
  const yBottom = ySupp + suppH + GAP

  const iconImage = await loadCanvasImage(REPORT_FAVICON_SRC)

  // single page tone everywhere
  ctx.fillStyle = c.bg
  ctx.fillRect(0, 0, PW, PH)

  // ---- header (same light tone, colourful accent rule) -------------------
  const Header = () => {
    ctx.fillStyle = c.headerBg
    ctx.fillRect(0, 0, PW, HB)
    const g1 = ctx.createRadialGradient(PW - 160, -20, 20, PW - 160, -20, 420)
    g1.addColorStop(0, 'rgba(255,255,255,0.6)')
    g1.addColorStop(1, 'rgba(255,255,255,0)')
    ctx.fillStyle = g1; ctx.fillRect(0, 0, PW, HB)

    const iconSize = 44
    fillRoundedRect(ctx, PAD, 30, iconSize, iconSize, 12, c.white)
    strokeRoundedRect(ctx, PAD, 30, iconSize, iconSize, 12, c.line, 1)
    if (iconImage) ctx.drawImage(iconImage, PAD + 5, 35, iconSize - 10, iconSize - 10)
    text(appName, PAD + iconSize + 16, 52, { size: 25, weight: '800', color: c.ink })
    text('Personal finance report', PAD + iconSize + 16, 71, { size: 11.5, weight: '600', color: c.sub })

    text(reportTitle, PAD, 138, { size: 40, weight: '800', color: c.ink })
    const pLabel = periodLabel || ''
    const pW = 30 + measure(pLabel, 14, '800') + 16
    fillRoundedRect(ctx, PAD, 156, pW, 34, 17, c.greenSoft)
    ctx.beginPath(); ctx.arc(PAD + 17, 156 + 17, 3.6, 0, Math.PI * 2); ctx.fillStyle = c.green; ctx.fill()
    text(pLabel, PAD + 30, 156 + 22, { size: 14, weight: '800', color: '#0b7a4e' })
    text(`Generated ${generatedAt}`, PAD, 206, { size: 12, weight: '600', color: c.muted })

    if (userEmail) text(userEmail, PW - PAD, 50, { size: 13.5, weight: '600', color: c.sub, align: 'right' })
    const good = safeNet >= 0
    const stTone = good ? c.green : c.red
    const stSoft = good ? c.greenSoft : c.redSoft
    const stW = measure(statusText, 13.5, '800') + 54
    const stX = PW - PAD - stW
    const stY = 70
    fillRoundedRect(ctx, stX, stY, stW, 40, 20, stSoft)
    strokeRoundedRect(ctx, stX, stY, stW, 40, 20, good ? '#c7e8d7' : '#f6cfcb', 1)
    ctx.beginPath(); ctx.arc(stX + 26, stY + 20, 11, 0, Math.PI * 2); ctx.fillStyle = c.white; ctx.fill()
    if (good) checkMark(stX + 26, stY + 20, stTone)
    else text('!', stX + 26, stY + 25, { size: 15, weight: '800', color: stTone, align: 'center' })
    text(statusText, stX + 44, stY + 25, { size: 13.5, weight: '800', color: good ? '#0b7a4e' : '#c0362f' })
  }

  // ---- KPI strip ---------------------------------------------------------
  const KpiCard = (x: number, title: string, value: string, tone: string, toneSoft: string, glyph: 'up' | 'down' | 'dollar' | 'pct', cur: number, prev: number | null | undefined, higherIsGood: boolean) => {
    const w = (CW - GAP * 3) / 4
    card(x, yKpi, w, kpiH, { r: 18 })
    fillRoundedRect(ctx, x, yKpi + 16, 4, kpiH - 32, 2, tone)
    fillRoundedRect(ctx, x + 20, yKpi + 22, 40, 40, 12, toneSoft)
    const gx = x + 40, gy = yKpi + 42
    if (glyph === 'up') arrow(gx, gy - 1, true, tone, 6)
    else if (glyph === 'down') arrow(gx, gy + 1, false, tone, 6)
    else text(glyph === 'dollar' ? '$' : '%', gx, gy + 6, { size: 19, weight: '800', color: tone, align: 'center' })
    text(title, x + 72, yKpi + 40, { size: 13, weight: '700', color: c.sub })
    text(value, x + 22, yKpi + 96, { size: 27, weight: '800', color: c.ink })
    const dy = yKpi + 120
    if (prev != null && Number.isFinite(prev) && prev > 0) {
      const d = ((cur - prev) / prev) * 100
      const up = d >= 0
      const isGood = up === higherIsGood
      const col = isGood ? c.green : c.red
      const bg = isGood ? c.greenSoft : c.redSoft
      const label = `${up ? '+' : ''}${d.toFixed(1)}%`
      fillRoundedRect(ctx, x + 22, dy, measure(label, 12, '800') + 26, 22, 11, bg)
      arrow(x + 22 + 12, dy + 11, up, col, 4)
      text(label, x + 22 + 22, dy + 15, { size: 12, weight: '800', color: col })
      if (previousMonthLabel) text(`vs ${previousMonthLabel}`, x + 22 + measure(label, 12, '800') + 34, dy + 15, { size: 11, weight: '600', color: c.muted })
    } else {
      text('Current period', x + 22, dy + 15, { size: 11.5, weight: '600', color: c.muted })
    }
  }
  const KpiRow = () => {
    const w = (CW - GAP * 3) / 4
    KpiCard(PAD, 'Total Income', fmtMoney(safeIncome), c.green, c.greenSoft, 'up', safeIncome, previousTotals?.income, true)
    KpiCard(PAD + (w + GAP), 'Total Expenses', fmtMoney(safeExpenses), c.red, c.redSoft, 'down', safeExpenses, previousTotals?.expenses, false)
    KpiCard(PAD + (w + GAP) * 2, 'Net Savings', fmtMoney(safeNet), safeNet >= 0 ? c.blue : c.red, safeNet >= 0 ? c.blueSoft : c.redSoft, 'dollar', safeNet, previousTotals?.balance, true)
    const prevRate = previousTotals && previousTotals.income > 0 ? (previousTotals.balance / previousTotals.income) * 100 : null
    KpiCard(PAD + (w + GAP) * 3, 'Savings Rate', fmtPct(savingsRate), c.violet, c.violetSoft, 'pct', savingsRate, prevRate, true)
  }

  // ---- Expense breakdown (donut) -----------------------------------------
  const ExpenseCard = () => {
    const x = colL, y = yCharts, w = colW, h = chartsH
    card(x, y, w, h)
    sectionTitle(x + 22, y + 34, 'Expense Breakdown', c.blue, 'Where your money went this period')
    const cx = x + 158, cy = y + 258
    const outer = 116, inner = 74
    const total = categoryRows.reduce((s, r) => s + r.value, 0) || 1
    let ang = -Math.PI / 2
    categoryRows.forEach((row) => {
      const slice = (row.value / total) * Math.PI * 2
      ctx.beginPath(); ctx.moveTo(cx, cy); ctx.arc(cx, cy, outer, ang, ang + slice); ctx.closePath(); ctx.fillStyle = row.color; ctx.fill()
      ctx.save(); ctx.strokeStyle = c.white; ctx.lineWidth = 2
      ctx.beginPath(); ctx.moveTo(cx, cy); ctx.lineTo(cx + Math.cos(ang) * outer, cy + Math.sin(ang) * outer); ctx.stroke(); ctx.restore()
      ang += slice
    })
    ctx.beginPath(); ctx.arc(cx, cy, inner, 0, Math.PI * 2); ctx.fillStyle = c.white; ctx.fill()
    text('TOTAL SPENT', cx, cy - 12, { size: 10.5, weight: '700', color: c.muted, align: 'center' })
    text(fmtMoney(safeExpenses), cx, cy + 16, { size: 24, weight: '800', color: c.ink, align: 'center' })
    text(`${categoryRows.length} categories`, cx, cy + 38, { size: 11, weight: '600', color: c.sub, align: 'center' })
    const lx = x + 300
    categoryRows.forEach((row, i) => {
      const yy = y + 96 + i * 44
      fillRoundedRect(ctx, lx, yy - 10, 12, 12, 4, row.color)
      text(row.label.length > 16 ? `${row.label.slice(0, 15)}…` : row.label, lx + 22, yy, { size: 13, weight: '700', color: c.text })
      text(fmtMoney(row.value, true), lx + 22, yy + 18, { size: 11.5, weight: '600', color: c.sub })
      text(`${Math.round(row.pct)}%`, x + w - 22, yy, { size: 13, weight: '800', color: row.color, align: 'right' })
    })
    fillRoundedRect(ctx, x + 20, y + h - 58, w - 40, 40, 12, c.soft)
    text('Total Expenses', x + 36, y + h - 33, { size: 13, weight: '700', color: c.sub })
    text(fmtMoney(safeExpenses, true), x + w - 36, y + h - 33, { size: 15, weight: '800', color: c.ink, align: 'right' })
  }

  // ---- Spending vs income (combo) ----------------------------------------
  const ComboCard = () => {
    const x = colR, y = yCharts, w = colW, h = chartsH
    card(x, y, w, h)
    sectionTitle(x + 22, y + 34, comboTitle || 'Spending vs Income', c.green, 'Cash flow across the period')
    const ly = y + 62
    fillRoundedRect(ctx, x + 22, ly, 20, 9, 4, c.green); text('Income', x + 48, ly + 8, { size: 11.5, weight: '600', color: c.sub })
    fillRoundedRect(ctx, x + 130, ly, 20, 9, 4, c.red); text('Expenses', x + 156, ly + 8, { size: 11.5, weight: '600', color: c.sub })
    line(x + 250, ly + 4, x + 276, ly + 4, c.blue, 2.4); ctx.beginPath(); ctx.arc(x + 263, ly + 4, 3, 0, Math.PI * 2); ctx.fillStyle = c.blue; ctx.fill()
    text('Net savings', x + 284, ly + 8, { size: 11.5, weight: '600', color: c.sub })

    const plotX = x + 66, plotY = y + 100, plotW = w - 100, plotH = 232
    const rawMax = Math.max(1, ...weekRows.map((r) => Math.max(Number(r.income || 0), Number(r.expenses || 0), Number(r.line || 0))))
    const maxValue = Math.max(2000, Math.ceil(rawMax / 2000) * 2000)
    const ticks = Math.min(5, Math.floor(maxValue / 2000)) || 1
    for (let i = 0; i <= ticks; i++) {
      const tv = (maxValue / ticks) * i
      const yy = plotY + plotH - (tv / maxValue) * plotH
      line(plotX, yy, plotX + plotW, yy, c.line)
      text(fmtMoney(tv).replace('.00', ''), plotX - 12, yy + 4, { size: 10.5, weight: '600', color: c.muted, align: 'right' })
    }
    const step = plotW / Math.max(1, weekRows.length)
    const pts: Array<{ x: number; y: number }> = []
    weekRows.forEach((row, i) => {
      const bx = plotX + i * step + step / 2
      const bw = 22
      const ih = (Math.max(0, Number(row.income || 0)) / maxValue) * plotH
      const eh = (Math.max(0, Number(row.expenses || 0)) / maxValue) * plotH
      fillRoundedRect(ctx, bx - bw - 3, plotY + plotH - ih, bw, ih, 5, c.green)
      fillRoundedRect(ctx, bx + 3, plotY + plotH - eh, bw, eh, 5, c.red)
      text(row.label, bx, plotY + plotH + 20, { size: 12, weight: '700', color: c.sub, align: 'center' })
      if (row.subLabel) text(row.subLabel, bx, plotY + plotH + 36, { size: 9.5, weight: '600', color: c.muted, align: 'center' })
      const nv = Number.isFinite(row.line) ? Math.max(0, Number(row.line)) : Math.max(0, Number(row.income || 0) - Number(row.expenses || 0))
      pts.push({ x: bx, y: plotY + plotH - (nv / maxValue) * plotH })
    })
    if (pts.length > 1) {
      ctx.beginPath(); pts.forEach((p, i) => (i ? ctx.lineTo(p.x, p.y) : ctx.moveTo(p.x, p.y)))
      ctx.strokeStyle = c.blue; ctx.lineWidth = 2.6; ctx.lineJoin = 'round'; ctx.stroke()
    }
    pts.forEach((p) => { ctx.beginPath(); ctx.arc(p.x, p.y, 4, 0, Math.PI * 2); ctx.fillStyle = c.white; ctx.fill(); ctx.strokeStyle = c.blue; ctx.lineWidth = 2.2; ctx.stroke() })

    const sy = y + h - 62
    fillRoundedRect(ctx, x + 20, sy, w - 40, 46, 12, c.soft)
    const cw = (w - 40) / 3
    text('INCOME', x + 36, sy + 17, { size: 10, weight: '700', color: c.muted }); text(fmtMoney(safeIncome), x + 36, sy + 37, { size: 15, weight: '800', color: c.green })
    text('EXPENSES', x + 36 + cw, sy + 17, { size: 10, weight: '700', color: c.muted }); text(fmtMoney(safeExpenses), x + 36 + cw, sy + 37, { size: 15, weight: '800', color: c.red })
    text('NET SAVINGS', x + 36 + cw * 2, sy + 17, { size: 10, weight: '700', color: c.muted }); text(fmtMoney(safeNet), x + 36 + cw * 2, sy + 37, { size: 15, weight: '800', color: safeNet >= 0 ? c.blue : c.red })
  }

  // ---- Goals progress (shows up to 3, closest to completion) -------------
  const GoalsCard = () => {
    const x = colL, y = ySupp, w = colW, h = suppH
    card(x, y, w, h)
    sectionTitle(x + 22, y + 34, 'Goals Progress', c.green, 'Closest to completion')
    const rows = (goalRows.length ? goalRows : [{ label: 'No goals yet', target: 1, current: 0, emoji: null }]).slice(0, 3)
    const tones = [c.green, c.blue, c.violet]
    const softs = [c.greenSoft, c.blueSoft, c.violetSoft]
    const rowH = 90
    const usable = h - 66 - 20
    const startY = y + 66 + Math.max(0, (usable - rows.length * rowH) / 2)
    rows.forEach((g, i) => {
      const gy = startY + i * rowH
      const tone = tones[i % 3], soft = softs[i % 3]
      const ratio = g.target > 0 ? Math.min(1, Math.max(0, g.current / g.target)) : 0
      card(x + 18, gy, w - 36, rowH - 14, { r: 14, fill: c.soft, stroke: c.line, shadow: false })
      fillRoundedRect(ctx, x + 34, gy + 17, 40, 40, 12, soft)
      text(g.emoji || '◎', x + 54, gy + 43, { size: 19, weight: '700', color: tone, align: 'center' })
      text(g.label.length > 22 ? `${g.label.slice(0, 21)}…` : g.label, x + 86, gy + 29, { size: 14, weight: '800', color: c.ink })
      text(`${fmtMoney(g.current)} of ${fmtMoney(g.target)}`, x + 86, gy + 49, { size: 11.5, weight: '600', color: c.sub })
      text(fmtPct(ratio * 100), x + w - 34, gy + 31, { size: 15, weight: '800', color: tone, align: 'right' })
      const barX = x + 86, barW = w - 130
      fillRoundedRect(ctx, barX, gy + 59, barW, 8, 4, '#dfe6f0')
      fillRoundedRect(ctx, barX, gy + 59, Math.max(8, barW * ratio), 8, 4, tone)
    })
  }

  // ---- Top categories ----------------------------------------------------
  const TopCatCard = () => {
    const x = colR, y = ySupp, w = colW, h = suppH
    card(x, y, w, h)
    sectionTitle(x + 22, y + 34, 'Top Categories', c.amber, 'Ranked by total spend')
    text('AMOUNT', x + w - 22, y + 34, { size: 10.5, weight: '700', color: c.muted, align: 'right' })
    const rows = categoryRows.slice(0, 6)
    const startY = y + 74
    const rowH = (h - 74 - 52) / Math.max(rows.length, 1)
    rows.forEach((row, i) => {
      const ry = startY + i * rowH + rowH / 2
      if (i > 0) line(x + 22, startY + i * rowH, x + w - 22, startY + i * rowH, c.line)
      fillRoundedRect(ctx, x + 22, ry - 13, 26, 26, 8, row.color)
      text(String(i + 1), x + 35, ry + 5, { size: 13, weight: '800', color: c.white, align: 'center' })
      text(row.label.length > 20 ? `${row.label.slice(0, 19)}…` : row.label, x + 60, ry + 5, { size: 13.5, weight: '700', color: c.text })
      text(fmtMoney(row.value, true), x + w - 78, ry + 5, { size: 13, weight: '800', color: c.ink, align: 'right' })
      text(`${Math.round(row.pct)}%`, x + w - 22, ry + 5, { size: 12.5, weight: '800', color: row.color, align: 'right' })
    })
    fillRoundedRect(ctx, x + 20, y + h - 54, w - 40, 38, 12, c.soft)
    text('Total', x + 36, y + h - 30, { size: 13, weight: '700', color: c.sub })
    text(fmtMoney(safeExpenses, true), x + w - 36, y + h - 30, { size: 15, weight: '800', color: c.ink, align: 'right' })
  }

  // ---- Recurring payments ------------------------------------------------
  const RecurringCard = () => {
    const x = colL, y = yBottom, w = colW, h = bottomH
    card(x, y, w, h)
    sectionTitle(x + 22, y + 34, 'Recurring Payments', c.violet, 'Subscriptions & scheduled items')
    text('ITEM', x + 22, y + 66, { size: 10.5, weight: '700', color: c.muted })
    text('FREQUENCY', x + w - 190, y + 66, { size: 10.5, weight: '700', color: c.muted })
    text('AMOUNT', x + w - 22, y + 66, { size: 10.5, weight: '700', color: c.muted, align: 'right' })
    const rows = recurringRows.slice(0, 4)
    if (!rows.length) text('No recurring payments tracked.', x + 22, y + 112, { size: 13, weight: '600', color: c.muted })
    const startY = y + 86
    const rowH = 50
    rows.forEach((row, i) => {
      const ry = startY + i * rowH + rowH / 2
      line(x + 22, startY + i * rowH, x + w - 22, startY + i * rowH, c.line)
      fillRoundedRect(ctx, x + 22, ry - 13, 26, 26, 8, c.violetSoft)
      text('↻', x + 35, ry + 6, { size: 15, weight: '700', color: c.violet, align: 'center' })
      const name = row.label.replace(/^[^\w]+\s*/, '')
      text(name.length > 22 ? `${name.slice(0, 21)}…` : name, x + 58, ry + 5, { size: 13.5, weight: '700', color: c.text })
      const cad = row.cadence === 'Bi-weekly' ? 'Every 2 weeks' : row.cadence === 'Monthly' ? 'Every month' : 'Every week'
      text(cad, x + w - 190, ry + 5, { size: 12, weight: '600', color: c.sub })
      text(fmtMoney(row.amount), x + w - 22, ry + 5, { size: 13.5, weight: '800', color: c.ink, align: 'right' })
    })
  }

  // ---- Key insights ------------------------------------------------------
  const InsightsCard = () => {
    const x = colR, y = yBottom, w = colW, h = bottomH
    card(x, y, w, h)
    sectionTitle(x + 22, y + 34, 'Key Insights', c.blue, 'Automated highlights from your data')
    const defaults = [
      `You saved ${fmtMoney(safeNet)} this period — a ${fmtPct(savingsRate)} savings rate.`,
      `${categoryRows[0]?.label || 'Top category'} led spending at ${Math.round(categoryRows[0]?.pct || 0)}% of expenses.`,
      'Keep tracking to unlock deeper trends and forecasts.',
    ]
    const items = (insights.length ? insights : defaults).slice(0, 3)
    const tones = [c.green, c.blue, c.violet]
    const softs = [c.greenSoft, c.blueSoft, c.violetSoft]
    const startY = y + 62
    const slot = (h - 62 - 24) / Math.max(items.length, 1)
    items.forEach((item, i) => {
      const iy = startY + i * slot + 6
      const tone = tones[i % 3], soft = softs[i % 3]
      fillRoundedRect(ctx, x + 22, iy, w - 44, slot - 14, 12, soft)
      const midY = iy + (slot - 14) / 2
      ctx.beginPath(); ctx.arc(x + 46, midY, 13, 0, Math.PI * 2); ctx.fillStyle = c.white; ctx.fill()
      if (i === 1) arrow(x + 46, midY - 1, true, tone, 5)
      else checkMark(x + 46, midY, tone)
      const maxW = w - 100
      const words = item.split(' ')
      let l1 = '', l2 = ''
      for (const word of words) {
        const t = l1 ? `${l1} ${word}` : word
        if (measure(t, 12.5, '600') <= maxW || !l1) l1 = t
        else { l2 = l2 ? `${l2} ${word}` : word }
      }
      if (l2 && measure(l2, 12.5, '600') > maxW) l2 = `${l2.slice(0, 46)}…`
      if (l2) {
        text(l1, x + 72, midY - 3, { size: 12.5, weight: '600', color: c.text })
        text(l2, x + 72, midY + 15, { size: 12.5, weight: '600', color: c.text })
      } else {
        text(l1, x + 72, midY + 5, { size: 12.5, weight: '600', color: c.text })
      }
    })
  }

  // ---- Footer (same tone, colourful accent rule) -------------------------
  const Footer = () => {
    const fy = PH - FB
    ctx.fillStyle = c.headerBg
    ctx.fillRect(0, fy, PW, FB)
    const lx = PAD, mid = fy + FB / 2 + 2
    strokeRoundedRect(ctx, lx, mid - 6, 14, 12, 3, c.sub, 1.6)
    ctx.beginPath(); ctx.arc(lx + 7, mid - 6, 5, Math.PI, 0); ctx.strokeStyle = c.sub; ctx.lineWidth = 1.6; ctx.stroke()
    text('End-to-end private • Your data never leaves your account', lx + 26, mid + 2, { size: 12, weight: '600', color: c.sub })
    text(`${appName} — Finances at your fingertips`, PW / 2, mid + 2, { size: 12.5, weight: '700', color: c.ink, align: 'center' })
    text('Page 1 of 1', PW - PAD, mid + 2, { size: 12, weight: '600', color: c.sub, align: 'right' })
  }

  Header()
  KpiRow()
  ExpenseCard()
  ComboCard()
  GoalsCard()
  TopCatCard()
  RecurringCard()
  InsightsCard()
  Footer()

  return canvas
}



