function DeleteConfirmModal({ open, itemLabel, onConfirm, onCancel }: { open: boolean; itemLabel: string; onConfirm: () => void; onCancel: () => void }) {
  if (!open) return null
  return (
    <div className="deleteConfirmBackdrop" role="presentation">
      <div className="card deleteConfirmModal" role="dialog" aria-modal="true" aria-labelledby="delete-confirm-title">
        <div className="deleteConfirmIcon" aria-hidden="true">!</div>
        <h3 id="delete-confirm-title">Are you sure?</h3>
        <p className="muted">This will permanently delete <strong>{itemLabel}</strong>. You won't be able to revert this.</p>
        <div className="deleteConfirmActions">
          <button className="btn danger" onClick={onConfirm}>Yes, delete it</button>
          <button className="btn" onClick={onCancel}>Cancel</button>
        </div>
      </div>
    </div>
  )
}

type DuplicateTransactionGroup = {
  key: string
  items: Transaction[]
}

function findDuplicateTransactionGroups(transactions: Transaction[]) {
  const map = new Map<string, Transaction[]>()
  transactions.forEach((transaction) => {
    const normalizedAmount = Number(Number(transaction.amount ?? 0).toFixed(2))
    const key = [transaction.date, transaction.type, transaction.category_id ?? '', normalizedAmount].join('|')
    const bucket = map.get(key) ?? []
    bucket.push(transaction)
    map.set(key, bucket)
  })

  return Array.from(map.entries())
    .filter(([, items]) => items.length > 1)
    .map(([key, items]) => ({ key, items }))
}

function DuplicateTransactionModal({
  open,
  group,
  catsById,
  currency,
  fmtMoney,
  onDiscard,
  onProceed,
  onCancel,
}: {
  open: boolean
  group: DuplicateTransactionGroup | null
  catsById: Map<string, Category>
  currency: string
  fmtMoney: (value: number, currency: string) => string
  onDiscard: (id: string) => void
  onProceed: () => void
  onCancel: () => void
}) {
  if (!open || !group) return null

  const categoryName = (transaction: Transaction) => transaction.category_id ? catsById.get(transaction.category_id)?.name ?? 'Unknown' : 'Uncategorized'

  return (
    <div className="deleteConfirmBackdrop" role="presentation">
      <div className="card deleteConfirmModal" role="dialog" aria-modal="true" aria-labelledby="duplicate-transaction-title" style={{ maxWidth: 760, width: 'min(760px, calc(100vw - 28px))' }}>
        <div className="deleteConfirmIcon" aria-hidden="true">!</div>
        <h3 id="duplicate-transaction-title">Possible Duplicate Transaction</h3>
        <p className="muted" style={{ maxWidth: 560, textAlign: 'center', margin: '0 auto 8px' }}>
          We found matching transactions with the same date, category, type, and amount. Review both entries below, discard the extra one if needed, or proceed anyway.
        </p>
        <div className="grid" style={{ gap: 12, marginTop: 10, width: '100%' }}>
          {group.items.map((transaction, index) => (
            <div key={transaction.id} className="card" style={{ background: 'rgba(255,255,255,.02)', border: '1px solid var(--line)', padding: 14, textAlign: 'left' }}>
              <div className="row between" style={{ alignItems: 'flex-start', gap: 12 }}>
                <div>
                  <div style={{ fontWeight: 800, marginBottom: 8 }}>Transaction {index + 1}</div>
                  <div className="grid" style={{ gap: 6 }}>
                    <div><strong>Date:</strong> {transaction.date}</div>
                    <div><strong>Type:</strong> <span style={{ textTransform: 'capitalize' }}>{transaction.type}</span></div>
                    <div><strong>Category:</strong> {categoryName(transaction)}</div>
                    <div><strong>Amount:</strong> {fmtMoney(transaction.amount, currency)}</div>
                    <div><strong>Note:</strong> {transaction.note?.trim() || 'No note'}</div>
                  </div>
                </div>
                <button className="btn danger" onClick={() => onDiscard(transaction.id)}>Discard</button>
              </div>
            </div>
          ))}
        </div>
        <div className="deleteConfirmActions" style={{ marginTop: 16 }}>
          <button className="btn primary" onClick={onProceed}>Proceed</button>
          <button className="btn" onClick={onCancel}>Cancel</button>
        </div>
      </div>
    </div>
  )
}


