function categoryIconFor(name?: string | null): LucideIcon {
  const normalized = (name ?? '').trim().toLowerCase()
  if (!normalized) return TagIcon
  for (const rule of CATEGORY_ICON_RULES) {
    if (rule.keywords.some((keyword) => normalized.includes(keyword))) return rule.icon
  }
  return TagIcon
}

function CategoryIcon({ name, size = 16, color, strokeWidth = 2 }: { name?: string | null; size?: number; color?: string; strokeWidth?: number }) {
  const Icon = categoryIconFor(name)
  return <Icon size={size} color={color} strokeWidth={strokeWidth} aria-hidden />
}

// Percentage-change delta chip vs the prior month. Color follows favorability:
// for income/net, up is good; for expenses, up is bad (invert).
function TrendDelta({ current, prev, invert = false }: { current: number; prev: number; invert?: boolean }) {
  const diff = current - prev
  if (!Number.isFinite(prev) || prev === 0) {
    return <span className="kpiDelta neutral"><Minus size={13} strokeWidth={2.5} />{current !== 0 ? <>New<span className="kpiDeltaSuffix"> vs last month</span></> : 'No prior data'}</span>
  }
  const pct = (diff / Math.abs(prev)) * 100
  const flat = Math.abs(pct) < 0.5
  const up = diff > 0
  const favorable = invert ? diff < 0 : diff > 0
  const Icon = flat ? Minus : up ? ArrowUpRight : ArrowDownRight
  const cls = flat ? 'neutral' : favorable ? 'up' : 'down'
  const sign = up ? '+' : ''
  return (
    <span className={`kpiDelta ${cls}`}>
      <Icon size={13} strokeWidth={2.5} />
      {flat ? '0%' : `${sign}${pct.toFixed(0)}%`}<span className="kpiDeltaSuffix"> vs last month</span>
    </span>
  )
}

const INCOME_CATEGORY_KEYWORDS = [
  'income', 'salary', 'pay', 'paycheck', 'bonus', 'refund', 'interest', 'dividend', 'freelance', 'commission', 'deposit', 'allowance', 'gift', 'rent income', 'side hustle', 'sale', 'sold', 'profit'
]

function getCategoryUsageType(categoryId: string, categoryName: string, transactions: Transaction[], recurring: RecurringItem[]): 'income' | 'expense' | 'both' {
  const hasIncomeTx = transactions.some((tx) => tx.category_id === categoryId && tx.type === 'income')
  const hasExpenseTx = transactions.some((tx) => tx.category_id === categoryId && tx.type === 'expense')
  const hasIncomeRecurring = recurring.some((item) => item.category_id === categoryId && item.kind === 'income')
  const hasExpenseRecurring = recurring.some((item) => item.category_id === categoryId && (item.kind === 'expense' || !item.kind))

  const hasIncome = hasIncomeTx || hasIncomeRecurring
  const hasExpense = hasExpenseTx || hasExpenseRecurring

  if (hasIncome && hasExpense) return 'both'
  if (hasIncome) return 'income'
  if (hasExpense) return 'expense'

  const normalized = categoryName.trim().toLowerCase()
  return INCOME_CATEGORY_KEYWORDS.some((keyword) => normalized.includes(keyword)) ? 'income' : 'expense'
}

function amountDisplay(amount: number, currency: string, type: TxType, fmtMoney: (amount: number, currency?: string) => string) {
  const safeAmount = Number(amount || 0)
  return `${type === 'income' ? '+' : '-'}${fmtMoney(Math.abs(safeAmount), currency)}`
}

function useMediaQuery(query: string) {
  const [matches, setMatches] = useState(() => (typeof window !== 'undefined' ? window.matchMedia(query).matches : false))

  useEffect(() => {
    const mediaQuery = window.matchMedia(query)
    const onChange = () => setMatches(mediaQuery.matches)
    onChange()
    if ('addEventListener' in mediaQuery) {
      mediaQuery.addEventListener('change', onChange)
      return () => mediaQuery.removeEventListener('change', onChange)
    }
    const legacy = mediaQuery as MediaQueryList & {
      addListener?: (listener: () => void) => void
      removeListener?: (listener: () => void) => void
    }
    legacy.addListener?.(onChange)
    return () => legacy.removeListener?.(onChange)
  }, [query])

  return matches
}

function useIsPhone() {
  return useMediaQuery('(max-width: 640px)')
}

function useIsCompactLaptop() {
  return useMediaQuery('(max-width: 1366px)')
}

function useIsTabletDown() {
  return useMediaQuery('(max-width: 768px)')
}



